/**
 * Payment Provider Configuration
 * 
 * Central registry of payment provider metadata including:
 * - Display names and descriptions
 * - Required client-side scripts
 * - Environment variable requirements
 * - Feature support flags
 */

export interface PaymentProviderConfig {
    /** Unique identifier matching PAYMENT_PROVIDER env var */
    id: string;
    /** Display name for admin UI */
    displayName: string;
    /** Short description of the provider */
    description: string;
    /** URL of the logo/icon */
    logoUrl?: string;
    /** Inline SVG for the provider logo (for use in components without external deps) */
    logoSvg?: string;
    /** Brand color (hex) */
    brandColor?: string;
    /** Client-side scripts to load (for embedded checkout) */
    scripts: {
        src: string;
        strategy?: 'beforeInteractive' | 'afterInteractive' | 'lazyOnload';
    }[];
    /** Required environment variables */
    requiredEnvVars: {
        key: string;
        label: string;
        isPublic: boolean; // NEXT_PUBLIC_ prefix
    }[];
    /** Supported features */
    features: {
        subscriptions: boolean;
        oneTimePayments: boolean;
        embeddedCheckout: boolean;
        customerPortal: boolean;
        coupons: boolean;
        refunds: boolean;
    };
    /** Webhook secret env var name */
    webhookSecretEnvVar: string;
    /** Supported currencies (ISO 4217 codes) */
    supportedCurrencies: string[];
    /** Documentation URL */
    docsUrl: string;
    /** Dashboard URL patterns for linking to external dashboards */
    dashboardUrls?: {
        /** Pattern for transaction/payment URLs. Use {id} placeholder. */
        transaction?: string;
        /** Pattern for subscription URLs. Use {id} placeholder. */
        subscription?: string;
        /** Pattern for customer URLs. Use {id} placeholder. */
        customer?: string;
    };
}

