/**
 * Get the active payment provider from environment
 */
export function getActivePaymentProvider(): string {
    return process.env.PAYMENT_PROVIDER || 'stripe';
}

/**
 * Get configuration for a specific provider
 */
export function getProviderConfig(providerId: string): PaymentProviderConfig | undefined {
    return PAYMENT_PROVIDERS[providerId];
}

/**
 * Get all available provider IDs
 */
export function getAvailableProviders(): string[] {
    return Object.keys(PAYMENT_PROVIDERS);
}

/**
 * Check if a provider has all required environment variables set
 */
export function isProviderConfigured(providerId: string): boolean {
    const config = PAYMENT_PROVIDERS[providerId];
    if (!config) return false;

    return config.requiredEnvVars.every(envVar => {
        const value = process.env[envVar.key];
        return value && value.length > 0 && !value.startsWith('xxx') && !value.startsWith('sk_test_xxx');
    });
}

/**
 * Get enabled providers (those with valid configuration)
 */
export function getEnabledProviders(): PaymentProviderConfig[] {
    return Object.values(PAYMENT_PROVIDERS).filter(p => isProviderConfigured(p.id));
}

/**
 * Build a dashboard URL for a provider resource
 * @param providerId - The payment provider ID (e.g., 'stripe', 'paystack')
 * @param type - The resource type ('transaction', 'subscription', 'customer')
 * @param id - The resource ID to insert into the URL pattern
 * @returns The full dashboard URL or null if not available
 */
export function buildDashboardUrl(
    providerId: string | null | undefined,
    type: 'transaction' | 'subscription' | 'customer',
    id: string | null | undefined
): string | null {
    if (!id || !providerId) return null;
    
    const config = PAYMENT_PROVIDERS[providerId.toLowerCase()];
    if (!config?.dashboardUrls) return null;
    
    const pattern = config.dashboardUrls[type];
    if (!pattern) return null;

    const url = pattern.replace('{id}', encodeURIComponent(id));

    // Paddle uses different vendor dashboard bases for sandbox vs production.
    if (providerId.toLowerCase() === 'paddle') {
        const env = (process.env.PADDLE_ENV || '').toLowerCase();
        const base = env === 'sandbox' ? 'https://sandbox-vendors.paddle.com' : 'https://vendors.paddle.com';
        return url.replace(/^https:\/\/vendors\.paddle\.com/, base);
    }

    return url;
}

/**
 * Check if a provider supports native coupons/promotion codes
 * @param providerId - The payment provider ID (e.g., 'stripe', 'paystack')
 * @returns true if the provider supports native coupons
 */
export function providerSupportsCoupons(providerId?: string | null): boolean {
    const id = providerId || getActivePaymentProvider();
    const config = PAYMENT_PROVIDERS[id.toLowerCase()];
    return config?.features?.coupons === true;
}

/**
 * Check if a provider supports a specific feature
 * @param providerId - The payment provider ID
 * @param feature - The feature to check
 * @returns true if the provider supports the feature
 */
export function providerSupportsFeature(
    providerId: string | null | undefined,
    feature: keyof PaymentProviderConfig['features']
): boolean {
    const id = providerId || getActivePaymentProvider();
    const config = PAYMENT_PROVIDERS[id.toLowerCase()];
    return config?.features?.[feature] === true;
}
